func safeGenerator(ctx context.Context) <-chan int {
    ch := make(chan int)
    go func() {
        defer close(ch)
        for i := 0; ; i++ {
            select {
            case ch <- i:
            case <-ctx.Done():
                return
            }
        }
    }()
    return ch
}

var (
    cache = make(map[string]int)
    mu    sync.Mutex
)

func increment(key string) {
    mu.Lock()
    cache[key]++
    mu.Unlock()
}
